import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import './AnimatedLogin.css';

const AnimatedLogin = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isPasswordFocused, setIsPasswordFocused] = useState(false);
  const [rotateHead, setRotateHead] = useState(0);
  const { login } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    // Añadir clase al body cuando el componente se monta
    document.body.classList.add('login-page');
    // Limpiar cuando el componente se desmonta
    return () => document.body.classList.remove('login-page');
  }, []);

  const handleUsernameChange = (e) => {
    setUsername(e.target.value);
    const length = Math.min(Math.max(e.target.value.length - 16, 0), 19);
    setRotateHead(-length);
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      await login(username, password);
      navigate('/home');
    } catch (error) {
      console.error('Login failed:', error);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
    const hands = document.querySelectorAll('.hand');
    hands.forEach(hand => {
      hand.classList.toggle('peek');
      hand.classList.toggle('hide');
    });
  };

  return (
    <div className="login-container">
      <div className="center">
        <div className="ear ear--left"></div>
        <div className="ear ear--right"></div>
        
        <div className="face" style={{ '--rotate-head': `${rotateHead}deg` }}>
          <div className="eyes">
            <div className="eye eye--left">
              <div className="glow"></div>
            </div>
            <div className="eye eye--right">
              <div className="glow"></div>
            </div>
          </div>
          
          <div className="nose">
            <svg width="38.161" height="22.03">
              <path 
                d="M2.017 10.987Q-.563 7.513.157 4.754C.877 1.994 2.976.135 6.164.093 16.4-.04 22.293-.022 32.048.093c3.501.042 5.48 2.081 6.02 4.661q.54 2.579-2.051 6.233-8.612 10.979-16.664 11.043-8.053.063-17.336-11.043z" 
                fill="#243946"
              />
            </svg>
            <div className="glow"></div>
          </div>

          <div className="mouth">
            <svg className="smile" viewBox="-2 -2 84 23" width="84" height="23">
              <path d="M0 0c3.76 9.279 9.69 18.98 26.712 19.238 17.022.258 10.72.258 28 0S75.959 9.182 79.987.161" 
                fill="none" 
                stroke="#243946"
                strokeWidth="3" 
                strokeLinecap="square" 
                strokeMiterlimit="3"
              />
            </svg>
            <div className="mouth-hole"></div>
            <div className={`tongue ${!isPasswordFocused ? 'breath' : ''}`}>
              <div className="tongue-top"></div>
              <div className="line"></div>
              <div className="median"></div>
            </div>
          </div>
        </div>

        <div className="hands">
          <div className="hand hand--left">
            <div className="finger">
              <div className="bone"></div>
              <div className="nail"></div>
            </div>
            <div className="finger">
              <div className="bone"></div>
              <div className="nail"></div>
            </div>
            <div className="finger">
              <div className="bone"></div>
              <div className="nail"></div>
            </div>
          </div>
          <div className="hand hand--right">
            <div className="finger">
              <div className="bone"></div>
              <div className="nail"></div>
            </div>
            <div className="finger">
              <div className="bone"></div>
              <div className="nail"></div>
            </div>
            <div className="finger">
              <div className="bone"></div>
              <div className="nail"></div>
            </div>
          </div>
        </div>

        <form className="login" onSubmit={handleLogin}>
          <label>
            <i className="fa fa-user"></i>
            <input 
              className="username" 
              type="text" 
              value={username}
              onChange={handleUsernameChange}
              placeholder="Username"
              autoComplete="username"
            />
          </label>
          
          <label>
            <i className="fa fa-lock"></i>
            <input 
              className="password" 
              type={showPassword ? 'text' : 'password'}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              onFocus={() => setIsPasswordFocused(true)}
              onBlur={() => setIsPasswordFocused(false)}
              placeholder="Password"
              autoComplete="current-password"
            />
            <button 
              type="button"
              className="password-button"
              onClick={togglePasswordVisibility}
            >
              {showPassword ? 'Hide' : 'Show'}
            </button>
          </label>
          
          <button type="submit" className="login-button">
            Login
          </button>
        </form>

        <div className="social-buttons">
          <div className="social">
            <i className="fa fa-wechat"></i>
          </div>
          <div className="social">
            <i className="fa fa-weibo"></i>
          </div>
          <div className="social">
            <i className="fa fa-paw"></i>
          </div>
        </div>

        <div className="footer">
          Welcome Back!
        </div>
      </div>
    </div>
  );
};

export default AnimatedLogin;
